// SocketPathInfo defines model for SocketPathInfo.
type SocketPathInfo struct {
	// ContainerdTtrpcBytes Canonical byte length of containerd's TTRPC socket
	// (<stateDir>/containerd/containerd.sock.ttrpc). Checked at
	// daemon startup by shortenStateDirIfNeeded; first thing to
	// trip on long paths.
	ContainerdTtrpcBytes *int `json:"containerd_ttrpc_bytes,omitempty"`

	// GvisorSocketDirChosenBytes Canonical byte length of the gvisor per-endpoint socket
	// directory actually configured on the running docker-next
	// server. The daemon picks between the primary candidate
	// (`~/.sbx/run`) and the `os.TempDir()/gvisor` fallback at
	// startup based on which fits the sun_path budget
	// (`resolveGvisorRootDir` in sandboxd/daemon.go). Omitted
	// when docker-next has not been configured yet (e.g. the
	// partial-error path where `info` is empty).
	GvisorSocketDirChosenBytes *int `json:"gvisor_socket_dir_chosen_bytes,omitempty"`

	// GvisorSocketDirPrimaryBytes Canonical byte length of the *primary* gvisor per-endpoint
	// socket directory candidate (`~/.sbx/run` plus any --app-name
	// suffix), regardless of whether the daemon actually chose it.
	// Highest-risk field: macOS expands /Users → /private/Users
	// (+8 bytes), which has silently pushed long-username
	// deployments past the limit in the past. Compare against
	// `gvisor_socket_dir_chosen_bytes`: when they differ, the
	// daemon fell back to the temp dir because the primary
	// blew the sun_path budget at startup.
	GvisorSocketDirPrimaryBytes *int `json:"gvisor_socket_dir_primary_bytes,omitempty"`

	// StateDirBytes Canonical byte length of the daemon's state directory
	// (`storagepaths.ResolveStateDir`). All sandboxd-managed
	// socket paths derive from this; longer values reduce the
	// margin every shim socket has under the sun_path limit.
	StateDirBytes *int `json:"state_dir_bytes,omitempty"`

	// SunPathLimitBytes Kernel AF_UNIX sockaddr_un.sun_path limit on this platform
	// (104 on macOS, 108 on Linux and Windows; 0 on other
	// platforms). Windows reports 108 because sandboxd still binds
	// an AF_UNIX-style containerd TTRPC socket there
	// (`shortenStateDirIfNeeded` enforces this budget at daemon
	// startup). Compare each *_bytes field below against
	// (limit - 1) to spot an imminent ENAMETOOLONG on bind/connect.
	SunPathLimitBytes int `json:"sun_path_limit_bytes"`

	// UsernameBytes Byte length (not rune count) of os/user.Current().Username
	// with USER / USERNAME / LOGNAME fallback. Multibyte usernames
	// consume more sun_path bytes than their visible character
	// count suggests.
	UsernameBytes *int `json:"username_bytes,omitempty"`
}

