// SyncCredentialsRequest defines model for SyncCredentialsRequest.
type SyncCredentialsRequest struct {
	// BindingsPath Absolute path to the user's credentials.yaml (the client's
	// resolved config-home location, e.g. $XDG_CONFIG_HOME/sbx/
	// credentials.yaml). The daemon reads binding authorization from
	// this file to decide which v2 credentials it may inject; it does
	// NOT fall back to its own process environment, which may differ
	// from the user's. Local-deployment only — a future cloud/multi-
	// tenant path replaces this with a verified authorization token.
	BindingsPath     *string            `json:"bindings_path,omitempty"`
	CredentialValues *[]CredentialValue `json:"credential_values,omitempty"`

	// CustomSecrets Custom secret mappings to install on the sandbox. The daemon
	// keeps the value for target-bound replacement in the proxy;
	// the sandbox process only ever sees `env_name=sentinel` so
	// the secret value never reaches the container.
	//
	// Sentinels must be non-empty and unique within the request —
	// duplicates and empty values are rejected with 400.
	CustomSecrets *[]CustomSecretValue `json:"custom_secrets,omitempty"`
}

// SyncCredentialsResult defines model for SyncCredentialsResult.
type SyncCredentialsResult struct {
	// Message Human-readable message describing the operation outcome.
	Message string `json:"message"`

	// Withheld Service identifiers whose v2 credential the daemon withheld at
	// sync because no binding authorized it. Service names only — no
	// values, paths, or domains. Empty/omitted when nothing was withheld.
	Withheld *[]string `json:"withheld,omitempty"`
}

